export default function ReviewsPage() {
  const featuredReview = reviews.find((item) => item.featured);
  const reviewGrid = reviews.filter((item) => !item.featured);

  return (
    <main className="bg-white">
      <section className="container mx-auto px-4 py-16 md:py-20">
        <div className="mx-auto max-w-3xl text-center">
          <p className="text-sm font-medium uppercase tracking-wide text-primary-suzuki">
            Customer Reviews
          </p>
          <h1 className="mt-3 font-suzuki-pro-headline text-4xl text-foreground md:text-5xl">
            Trusted by Suzuki drivers across Indonesia
          </h1>
          <p className="mt-4 text-base text-gray-600 md:text-lg">
            Real stories from customers who found their best-fit Suzuki with
            our team.
          </p>
        </div>

        <div className="mt-12 grid grid-cols-1 gap-4 sm:grid-cols-2 md:grid-cols-3 auto-rows-fr">
          {featuredReview && (
            <div className="sm:row-span-2 min-h-[300px]">
              <ReviewCard review={featuredReview} className="h-full" />
            </div>
          )}
          {reviewGrid.map((review) => (
            <div key={review.id} className="min-h-[220px]">
              <ReviewCard review={review} className="h-full" />
            </div>
          ))}
        </div>
      </section>
    </main>
  );
}

function ReviewCard({
  review,
  className = "",
}: {
  review: ReviewItem;
  className?: string;
}) {
  const isFeatured = Boolean(review.featured);

  return (
    <article
      className={`flex flex-col gap-4 rounded-2xl p-6 ${
        isFeatured
          ? "bg-foreground text-white"
          : "border border-gray-200 bg-gray-100 text-foreground"
      } ${className}`.trim()}
    >
      <div className="relative h-44 w-full overflow-hidden rounded-xl">
        <Image
          src={review.photoUrl}
          alt={`${review.name} testimonial customer photo`}
          fill
          className="object-cover"
          sizes="(max-width: 768px) 100vw, 420px"
        />
      </div>

      <div className="flex items-center justify-between gap-3">
        <div>
          <p
            className={`text-sm font-semibold ${isFeatured ? "text-white" : "text-foreground"}`}
          >
            {review.name}
          </p>
          <p className={`text-xs ${isFeatured ? "text-white/80" : "text-gray-500"}`}>
            {review.city} - {review.car}
          </p>
        </div>

        <span
          className={`inline-flex items-center gap-1 text-sm font-medium ${
            isFeatured ? "text-white" : "text-foreground"
          }`}
        >
          {review.rating}
          <Star className="h-4 w-4 fill-amber-400 text-amber-400" />
        </span>
      </div>

      <p
        className={`font-sans leading-relaxed ${
          isFeatured ? "text-base text-white" : "text-sm text-gray-700"
        }`}
      >
        &ldquo;{review.quote}&rdquo;
      </p>
    </article>
  );
}
